const d1  = $('Buscar Hoje').first().json;
const d7  = $('Buscar Semana').first().json;
const d30 = $('Buscar 30 dias').first().json;
const d90 = $input.first().json;
const pergunta = $('Filtro Mensagem').first().json.body.data.message.conversation;
const grupoJid = $('Filtro Mensagem').first().json.body.data.key.remoteJid;

function fmt(s) {
  const [y, m, d] = s.split('-'); return d + '/' + m + '/' + y;
}
function fmtShort(s) {
  const [y, m, d] = s.split('-'); return d + '/' + m;
}
function brl(v) {
  const parts = parseFloat(v).toFixed(2).split('.');
  parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return 'R$ ' + parts[0] + ',' + parts[1];
}
function pct(a, b) {
  if (!b) return '0,00'; return (a / b * 100).toFixed(2).replace('.', ',');
}
function deltaLabel(v) {
  return parseFloat(v) >= 0 ? 'delta positivo de' : 'delta negativo de';
}

const u1 = d1.usuarios;
const taxaConversao = Math.round(u1.investindo / u1.total * 100);
const pendentes = d1.financeiro.saques_pendentes || 0;

const meses = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];
function fmtMes(s) {
  const [y, m] = s.split('-'); return meses[parseInt(m,10)-1] + '/' + y;
}
const projecao = (d1.projecao_6_meses || []).map(function(p) {
  return fmtMes(p.mes) + ': ' + brl(p.total_previsto);
}).join(', ');

return [{ json: { grupoJid, chatInput: [
  'Voce e um assistente executivo da Purg. Responda a pergunta do socio de forma direta e concisa.',
  'Se o socio perguntar o que voce sabe, o que pode responder ou quais informacoes tem, liste em bullet points:',
  '- Total de usuarios cadastrados e quantos estao investindo (taxa de conversao)',
  '- Novos cadastros do dia',
  '- Depositos, saques e delta do dia',
  '- Saques pendentes e volume total investido',
  '- Novos usuarios e movimentacao financeira dos ultimos 7 dias',
  '- Novos usuarios e movimentacao financeira dos ultimos 30 dias',
  '- Novos usuarios e movimentacao financeira dos ultimos 90 dias',
  '- Projecao de metas para os proximos 6 meses (quando houver)',
  'Regras: texto simples, sem markdown, sem asteriscos; numeros sempre em algarismos;',
  'valores monetarios com formato brasileiro (ex: R$ 1.200,50); datas no formato DD/MM/YYYY.',
  '',
  'Data de referencia: ' + fmt(d1.data_referencia),
  '',
  'HOJE:',
  '- Usuarios: ' + u1.total + ' (investindo: ' + u1.investindo + ', taxa de conversao: ' + taxaConversao + '%)',
  '- Novos cadastros hoje: ' + u1.novos,
  '- Depositos: ' + brl(d1.financeiro.depositos) + ' | Saques: ' + brl(d1.financeiro.saques) + ' | ' + deltaLabel(d1.financeiro.delta) + ' ' + brl(d1.financeiro.delta),
  '- Saques pendentes: ' + pendentes,
  '- Volume investido: ' + brl(d1.financeiro.volume_investido),
  '',
  'ULTIMOS 7 DIAS (' + fmtShort(d7.data_inicio) + ' a ' + fmtShort(d7.data_referencia) + '):',
  '- Novos usuarios: ' + d7.usuarios.novos + ' (aumento de ' + pct(d7.usuarios.novos, d7.usuarios.total - d7.usuarios.novos) + '%)',
  '- Depositos: ' + brl(d7.financeiro.depositos) + ' | Saques: ' + brl(d7.financeiro.saques) + ' | ' + deltaLabel(d7.financeiro.delta) + ' ' + brl(d7.financeiro.delta),
  '',
  'ULTIMOS 30 DIAS (' + fmtShort(d30.data_inicio) + ' a ' + fmtShort(d30.data_referencia) + '):',
  '- Novos usuarios: ' + d30.usuarios.novos + ' (aumento de ' + pct(d30.usuarios.novos, d30.usuarios.total - d30.usuarios.novos) + '%)',
  '- Depositos: ' + brl(d30.financeiro.depositos) + ' | Saques: ' + brl(d30.financeiro.saques) + ' | ' + deltaLabel(d30.financeiro.delta) + ' ' + brl(d30.financeiro.delta),
  '',
  'ULTIMO TRIMESTRE (' + fmtShort(d90.data_inicio) + ' a ' + fmtShort(d90.data_referencia) + '):',
  '- Novos usuarios: ' + d90.usuarios.novos + ' (aumento de ' + pct(d90.usuarios.novos, d90.usuarios.total - d90.usuarios.novos) + '%)',
  '- Depositos: ' + brl(d90.financeiro.depositos) + ' | Saques: ' + brl(d90.financeiro.saques) + ' | ' + deltaLabel(d90.financeiro.delta) + ' ' + brl(d90.financeiro.delta),
  '',
  projecao ? 'PROJECAO METAS (6 meses): ' + projecao : '',
  '',
  'Pergunta do socio: ' + pergunta,
].join('\n') } }];

